import json
from collections import defaultdict

# Load complete package data
all_pkg_file = locals()['var_functions.query_db:26']
with open(all_pkg_file, 'r') as f:
    all_packages = json.load(f)

print('Total NPM packages in database:', len(all_packages))

# Find latest release version for each package
latest_pkgs = {}
for pkg in all_packages:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease', False):
            name = pkg['Name']
            ts = float(pkg['UpstreamPublishedAt'])
            if name not in latest_pkgs or ts > latest_pkgs[name]['ts']:
                latest_pkgs[name] = {
                    'name': name,
                    'version': pkg['Version'],
                    'ts': ts
                }
    except:
        pass

print('Latest release packages found:', len(latest_pkgs))

# Load project_packageversion data
ppv_file = locals()['var_functions.query_db:32']
with open(ppv_file, 'r') as f:
    ppv_records = json.load(f)

print('Total PPV records:', len(ppv_records))

# Build lookup map
ppv_map = {}
for record in ppv_records:
    key = (record['Name'], record['Version'])
    if key not in ppv_map:
        ppv_map[key] = record['ProjectName']

print('PPV lookup map size:', len(ppv_map))

# Match packages with projects
matched = []
for pkg_info in latest_pkgs.values():
    key = (pkg_info['name'], pkg_info['version'])
    if key in ppv_map:
        matched.append({
            'name': pkg_info['name'],
            'version': pkg_info['version'],
            'project': ppv_map[key]
        })

print('Successfully matched packages:', len(matched))

result_data = {'matched': matched}
print('__RESULT__:')
print(json.dumps(result_data))

